
public class Number_Divisible {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int n = 10;
		if(n % 3 == 0  && n % 5 == 0)
		{
			System.out.println("sanju weds Geetha");
		}
		else if(n % 3 == 0)
		{
			System.out.println("sanju");
		}
		else if (n % 5 == 0) 
		{
			System.out.println("Geetha");
		}

	}

}
